import anthropic, json

client = anthropic.Anthropic()

CONSTRAINT_SPEC_TOOL = {
    "name": "write_prompt_constraint",
    "description": "Write a prompt-level constraint to mitigate a specific risk",
    "input_schema": {
        "type": "object",
        "required": ["risk_id", "constraint_text", "placement",
                     "verification_eval", "expected_pass_rate"],
        "properties": {
            "risk_id": {"type": "string"},
            "constraint_text": {
                "type": "string",
                "description": "The exact text to add to the system prompt"
            },
            "placement": {
                "enum": ["beginning", "after_role_definition", "before_output_format", "end"],
                "description": "Where in the system prompt to insert the constraint"
            },
            "verification_eval": {
                "type": "string",
                "description": "Name of the eval case that will verify this constraint is working"
            },
            "expected_pass_rate": {
                "type": "number",
                "description": "Minimum pass rate (0-1) on the verification eval for the mitigation to be considered effective"
            },
            "anti_patterns_avoided": {
                "type": "array",
                "description": "Common constraint-writing mistakes this formulation avoids",
                "items": {"type": "string"}
            }
        }
    }
}

def write_prompt_constraint(risk_id, risk_description, current_system_prompt):
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=1024,
        tools=[CONSTRAINT_SPEC_TOOL],
        tool_choice={"type": "tool", "name": "write_prompt_constraint"},
        messages=[{
            "role": "user",
            "content": (
                f"Write a system prompt constraint to mitigate risk {risk_id}.\n\n"
                f"Risk description: {risk_description}\n\n"
                f"Current system prompt:\n{current_system_prompt}\n\n"
                "Constraint writing rules:\n"
                "1. State what TO DO, not just what not to do\n"
                "2. Be specific — 'avoid harm' is not a constraint; 'do not make claims about "
                "medical dosages' is a constraint\n"
                "3. Do not duplicate existing instructions\n"
                "4. Place near the role definition for identity constraints, "
                "near output format for format constraints\n"
                "5. Verify the constraint doesn't conflict with must-do items"
            )
        }]
    )
    for block in response.content:
        if block.type == "tool_use":
            return block.input
    raise RuntimeError("No tool use in response")

import anthropic, json
from pydantic import BaseModel, field_validator, ValidationError
from typing import Literal

client = anthropic.Anthropic()

# Example: tight schema for a medical triage output
# Enum fields prevent hallucination of invalid urgency levels
class TriageOutput(BaseModel):
    urgency: Literal["immediate", "urgent", "semi_urgent", "non_urgent"]
    reason: str
    recommended_action: str
    escalate_to_human: bool

    @field_validator("reason")
    @classmethod
    def reason_must_be_non_empty(cls, v):
        if not v.strip():
            raise ValueError("reason cannot be empty")
        return v

TRIAGE_TOOL = {
    "name": "classify_triage",
    "description": "Classify patient urgency for triage routing",
    "input_schema": {
        "type": "object",
        "required": ["urgency", "reason", "recommended_action", "escalate_to_human"],
        "properties": {
            "urgency": {
                "enum": ["immediate", "urgent", "semi_urgent", "non_urgent"],
                "description": "Must be one of these four values — no other string is valid"
            },
            "reason": {
                "type": "string",
                "minLength": 10,
                "description": "Why this urgency level was assigned"
            },
            "recommended_action": {"type": "string"},
            "escalate_to_human": {"type": "boolean"}
        }
    }
}

def classify_with_validation(patient_description):
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        tools=[TRIAGE_TOOL],
        tool_choice={"type": "tool", "name": "classify_triage"},
        messages=[{"role": "user", "content": patient_description}]
    )

    for block in response.content:
        if block.type == "tool_use":
            try:
                validated = TriageOutput(**block.input)
                return validated.model_dump()
            except ValidationError as e:
                raise ValueError(f"Schema validation failed: {e}")
    raise RuntimeError("No tool use in response")

import anthropic, json

client = anthropic.Anthropic()

CONFIDENCE_GATE_TOOL = {
    "name": "evaluate_with_confidence",
    "description": "Evaluate a query and return a confidence score alongside the response",
    "input_schema": {
        "type": "object",
        "required": ["response", "confidence", "confidence_factors",
                     "route_to_human", "routing_reason"],
        "properties": {
            "response": {"type": "string"},
            "confidence": {
                "type": "number",
                "minimum": 0.0,
                "maximum": 1.0,
                "description": "0=completely uncertain, 1=certain"
            },
            "confidence_factors": {
                "type": "array",
                "items": {"type": "string"},
                "description": "What specific factors raised or lowered confidence"
            },
            "route_to_human": {
                "type": "boolean",
                "description": "True if confidence < threshold or query type requires human"
            },
            "routing_reason": {"type": "string"}
        }
    }
}

CONFIDENCE_THRESHOLD = 0.75

def respond_with_gating(user_query, system_prompt, human_queue):
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=1024,
        system=system_prompt,
        tools=[CONFIDENCE_GATE_TOOL],
        tool_choice={"type": "tool", "name": "evaluate_with_confidence"},
        messages=[{"role": "user", "content": user_query}]
    )

    for block in response.content:
        if block.type == "tool_use":
            result = block.input
            if result["route_to_human"] or result["confidence"] < CONFIDENCE_THRESHOLD:
                ticket = human_queue.enqueue({
                    "query": user_query,
                    "draft_response": result["response"],
                    "confidence": result["confidence"],
                    "reason": result["routing_reason"]
                })
                return {"status": "queued", "ticket_id": ticket.id}
            return {"status": "responded", "response": result["response"]}

    raise RuntimeError("No tool use in response")

import anthropic, json

client = anthropic.Anthropic()

MITIGATION_SPEC_TOOL = {
    "name": "generate_mitigation_spec",
    "description": "Generate a buildable mitigation specification from a risk register entry",
    "input_schema": {
        "type": "object",
        "required": ["risk_id", "strategy", "implementation_spec",
                     "verification_method", "success_threshold",
                     "fallback", "owner", "sprint_target"],
        "properties": {
            "risk_id": {"type": "string"},
            "strategy": {
                "enum": ["prompt_constraint", "schema_validation",
                         "confidence_gating", "canary_rollout", "combined"]
            },
            "implementation_spec": {
                "type": "string",
                "description": "Exact change to implement: prompt text, schema change, or infrastructure spec"
            },
            "verification_method": {"type": "string"},
            "success_threshold": {"type": "string"},
            "fallback": {"type": "string"},
            "owner": {"type": "string"},
            "sprint_target": {"type": "string"},
            "estimated_effort_days": {"type": "number"},
            "dependencies": {"type": "array", "items": {"type": "string"}}
        }
    }
}

def generate_mitigation_specs(risk_register, team_roster):
    specs = []
    for risk in risk_register["risks"]:
        if risk["status"] in ("OPEN", "MITIGATED"):
            response = client.messages.create(
                model="claude-haiku-4-5-20251001",
                max_tokens=1024,
                tools=[MITIGATION_SPEC_TOOL],
                tool_choice={"type": "tool", "name": "generate_mitigation_spec"},
                messages=[{
                    "role": "user",
                    "content": (
                        f"Generate a buildable mitigation spec for:\n"
                        f"{json.dumps(risk, indent=2)}\n\n"
                        f"Team roster (use for owner assignment):\n"
                        f"{json.dumps(team_roster)}\n\n"
                        "Select the lowest-cost strategy that sufficiently reduces the risk. "
                        "Be specific: implementation_spec must contain the exact prompt text, "
                        "schema field change, or infrastructure configuration — not just a description. "
                        "success_threshold must be quantitative."
                    )
                }]
            )
            for block in response.content:
                if block.type == "tool_use":
                    specs.append(block.input)
                    break
    return specs

import anthropic, json, subprocess

client = anthropic.Anthropic()

VERIFICATION_RESULT_TOOL = {
    "name": "record_mitigation_verification",
    "description": "Record the verification result for a mitigation implementation",
    "input_schema": {
        "type": "object",
        "required": ["risk_id", "mitigation_spec_id", "eval_run_id",
                     "pass_rate", "threshold", "verification_passed",
                     "updated_risk_status", "residual_rpn"],
        "properties": {
            "risk_id": {"type": "string"},
            "mitigation_spec_id": {"type": "string"},
            "eval_run_id": {"type": "string"},
            "pass_rate": {"type": "number"},
            "threshold": {"type": "number"},
            "verification_passed": {"type": "boolean"},
            "updated_risk_status": {
                "enum": ["MITIGATED", "OPEN", "ACCEPTED"]
            },
            "residual_rpn": {"type": "integer"},
            "notes": {"type": "string"}
        }
    }
}

def verify_mitigation(risk_id, mitigation_spec, eval_suite_path):
    # Run the eval suite
    result = subprocess.run(
        ["python3", eval_suite_path, "--risk", risk_id],
        capture_output=True, text=True
    )
    eval_output = json.loads(result.stdout)

    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        tools=[VERIFICATION_RESULT_TOOL],
        tool_choice={"type": "tool", "name": "record_mitigation_verification"},
        messages=[{
            "role": "user",
            "content": (
                f"Record the mitigation verification result.\n\n"
                f"Risk ID: {risk_id}\n"
                f"Mitigation spec: {json.dumps(mitigation_spec)}\n"
                f"Eval output: {json.dumps(eval_output)}\n\n"
                "Rules: verification_passed = True if pass_rate >= threshold. "
                "updated_risk_status = MITIGATED if verification_passed, else OPEN. "
                "residual_rpn = original_rpn * (1 - risk_reduction) where risk_reduction "
                "is estimated from the pass_rate improvement."
            )
        }]
    )
    for block in response.content:
        if block.type == "tool_use":
            return block.input
    raise RuntimeError("No tool use in response")
